  &reftitle.examples;



    Memcache::append example


<?php
/* OO API */

$memcache_obj = new Memcache;
$memcache_obj->connect('memcache_host', 11211);

/* the item must already exist */
$memcache_obj->set('greeting', 'Hello');

/* append to the existing value */
$memcache_obj->append('greeting', ', World');

echo $memcache_obj->get('greeting');
/* outputs: Hello, World */

?>




    memcache_append example


<?php
/* procedural API */

$memcache_obj = memcache_connect('memcache_host', 11211);

memcache_set($memcache_obj, 'greeting', 'Hello');
memcache_append($memcache_obj, 'greeting', ', World');

echo memcache_get($memcache_obj, 'greeting');
/* outputs: Hello, World */

?>
